def get_ip():
    s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    try:
        s.connect(("8.8.8.8", 80))
        return s.getsockname()[0]
    except:
        return "127.0.0.1"
    finally:
        s.close()

def _set_print_settings(ws, last_row=50, last_col=8):
    """Standard print settings: portrait, fit to 1 page A4, normal margins."""
    from openpyxl.utils import get_column_letter
    from openpyxl.worksheet.page import PageMargins
    from openpyxl.worksheet.properties import WorksheetProperties, PageSetupProperties
    # Enable fitToPage via sheet properties
    if ws.sheet_properties is None:
        ws.sheet_properties = WorksheetProperties()
    ws.sheet_properties.pageSetUpPr = PageSetupProperties(fitToPage=True)
    ws.page_setup.orientation = 'portrait'
    ws.page_setup.fitToHeight = 1
    ws.page_setup.fitToWidth = 1
    ws.page_setup.paperSize = 9  # A4
    ws.page_margins = PageMargins(
        left=0.5, right=0.5, top=0.75, bottom=0.75, header=0.3, footer=0.3
    )
    ws.print_area = f"A1:{get_column_letter(last_col)}{last_row}"


def fmt_fecha(iso):
    if not iso: return ""
    meses = ["enero","febrero","marzo","abril","mayo","junio","julio","agosto",
             "septiembre","octubre","noviembre","diciembre"]
    try:
        y, mo, d = iso.split("-")
        return "San Juan, " + str(int(d)) + " de " + meses[int(mo)-1] + " del " + y
    except:
        return iso

def next_year(iso):
    if not iso: return ""
    try:
        d = datetime.strptime(iso, "%Y-%m-%d")
        return d.replace(year=d.year+1).strftime("%d/%m/%Y")
    except:
        return ""

_TMP = []

def add_logo_to_ws(ws, w=80, h=40, use_report_logo=True):
    try:
        from openpyxl.drawing.image import Image as XLImg
        raw = base64.b64decode(LOGO_REPORT_B64 if use_report_logo else LOGO_B64)
        suf = ".jpg" if raw[:2] == b"\xff\xd8" else ".png"
        tmp = tempfile.NamedTemporaryFile(suffix=suf, delete=False)
        tmp.write(raw); tmp.flush(); tmp.close()
        _TMP.append(tmp.name)
        img = XLImg(tmp.name)
        img.width = w; img.height = h; img.anchor = "A1"
        ws.add_image(img)
    except:
        pass

def cleanup_tmp():
    while _TMP:
        try: os.unlink(_TMP.pop())
        except: pass

